#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_N 200
#define MAX_T 100

int compare(const void *a, const void *b) {
    int *x = (int *)a;
    int *y = (int *)b;
    if (x[0] < y[0]) return -1;
    if (x[0] > y[0]) return 1;
    return 0;
}

int main() {
    int T, N, X;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &X);
        int Si[N], Ei[N];
        for (int i = 0; i < N; i++) {
            scanf("%d %d", &Si[i], &Ei[i]);
        }
        int graph[N][N] = {{0}};
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                if (Si[i] <= Ei[j] && Si[j] <= Ei[i]) {
                    graph[i][j] = graph[j][i] = 1;
                }
            }
        }
        int min_vertex_cover = N;
        for (int mask = 0; mask < (1 << N); mask++) {
            int cover = 0;
            for (int i = 0; i < N; i++) {
                if ((mask & (1 << i)) != 0) cover++;
            }
            int is_valid = 1;
            for (int i = 0; i < N; i++) {
                for (int j = i + 1; j < N; j++) {
                    if (graph[i][j] == 1 && (mask & (1 << i)) == 0 && (mask & (1 << j)) == 0) {
                        is_valid = 0;
                        break;
                    }
                }
                if (is_valid == 0) break;
            }
            if (is_valid == 1 && cover < min_vertex_cover) {
                min_vertex_cover = cover;
            }
        }
        printf("%d\n", min_vertex_cover);
    }
    return 0;
}

